    internal class ReciboCompra
    {
        string code;
        double total, subtotal, iva, tipoDouble;
        string contraseña = Environment.GetEnvironmentVariable("SMRC_PASS");
        DateTime fecha = DateTime.Now;

        public void Cálculos(string tipo, double cantidad)
        {
            switch (tipo)
            {
                case "Regular":
                    tipoDouble = 23.89;
                    break;
                case "Premium":
                    tipoDouble = 27.54;
                    break;
                case "Diesel":
                    tipoDouble = 31.59;
                    break;
            }
            total = cantidad * tipoDouble;
            iva = total * 0.16;
            subtotal = total - iva;
        }

        public void GenerarCódigo()
        {
            const string cadena = "0123456789";
            char[] resultado = new char[15];
            using (var rng = RandomNumberGenerator.Create())
            {
                byte[] datos = new byte[15];
                rng.GetBytes(datos);
                for (int i = 0; i < 6; i++)
                {
                    resultado[i] = cadena[datos[i] % cadena.Length];
                }
            }
            code = new string(resultado);
        }

